# Build final JSON
result = []
for art in articles_data:
    uuid_match = re.search(r'uuid=([a-f0-9]+)', art["url"])
    if uuid_match:
        uuid = uuid_match.group(1)
        content = contents.get(uuid, "")
    else:
        # For article URLs, extract from path
        path_parts = art["url"].split("/")
        article_id = path_parts[-1]
        content = contents.get(article_id, "")
    
    char_count = len(content)
    result.append({
        "url": art["url"],
        "title": art["title"],
        "content": content,
        "char_count": char_count,
        "category": art["category"]
    })

# Filter out articles with very short content (< 50 chars)
filtered = [a for a in result if a["char_count"] >= 50]

# Stats
total_chars = sum(a["char_count"] for a in filtered)
print(f"Total articles: {len(filtered)}")
print(f"Total chars: {total_chars}")
print(f"Articles with < 50 chars: {len(result) - len(filtered)}")
print(f"Average chars per article: {total_chars // len(filtered) if filtered else 0}")

# Save
output_path = r"D:\职业规划\职业规划\backend\app\crawlers\real_data\round5_kaoyan.json"
with open(output_path, "w", encoding="utf-8") as f:
    json.dump(filtered, f, ensure_ascii=False, indent=2)

print(f"\nSaved to: {output_path}")
